'use server';

import { updateTag } from 'next/cache';
import { addPost } from './lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title || !content) {
    throw new Error('Title and content are required');
  }

  addPost(title, content);

  // Immediately expire the 'posts' cache tag.
  // Unlike revalidateTag (which uses stale-while-revalidate and serves stale
  // content while fetching fresh data in the background), updateTag guarantees
  // that the next request blocks and waits for fresh data — no stale content
  // is ever served to the user.
  updateTag('posts');
}

