import { getPosts } from './lib/data';
import { createPost } from './actions';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main>
      <h1>Posts</h1>

      <form action={createPost}>
        <label>
          Title: <input name="title" placeholder="Enter a title" required />
        </label>
        <label>
          Content: <input name="content" placeholder="Enter content" required />
        </label>
        <button type="submit">Create Post</button>
      </form>

      <ul>
        {posts.map((post) => (
          <li key={post.id}>
            <h2>{post.title}</h2>
            <p>{post.content}</p>
          </li>
        ))}
      </ul>
    </main>
  );
}

